+#[test]
+fn sched_setaffinity_invalid_pid_zero_cpusetsize_sets_esrch_like_host() {
+    let _guard = SCHED_AFFINITY_TEST_GUARD
+        .lock()
+        .expect("affinity test guard lock should succeed");
+    let mut cpuset: libc::cpu_set_t = unsafe { std::mem::zeroed() };
+
+    assert_eq!(
+        unsafe {
+            sched_getaffinity(
+                0,
+                std::mem::size_of::<libc::cpu_set_t>(),
+                (&mut cpuset as *mut libc::cpu_set_t).cast(),
+            )
+        },
+        0
+    );
+
+    unsafe {
+        *libc::__errno_location() = 0;
+    }
+    let host_rc =
+        unsafe { libc::sched_setaffinity(-1, 0, (&cpuset as *const libc::cpu_set_t).cast()) };
+    let host_err = unsafe { *libc::__errno_location() };
+
+    unsafe {
+        *__errno_location() = 0;
+    }
+    let abi_rc = unsafe { sched_setaffinity(-1, 0, (&cpuset as *const libc::cpu_set_t).cast()) };
+    let abi_err = unsafe { *__errno_location() };
+
+    assert_eq!(host_rc, -1);
+    assert_eq!(abi_rc, host_rc);
+    assert_eq!(abi_err, host_err);
+    assert_eq!(abi_err, libc::ESRCH);
+}
